const body = $input.first().json.query

const validTypes = ['vo_register', 'action_summary', 'monthly_report', 'submission_log_register', 'dcn', 'si', 'vo'];

if (!String(body.document_type) || !validTypes.includes(String(body.document_type))) {
  return {
    json: {
      error: true,
      message: 'Invalid document_type. Must be one of: ' + validTypes.join(', ')
    }
  };
}

if (body.document_type !== 'monthly_report' && !body.project_id) {
  return {
    json: {
      error: true,
      message: 'project_id is required for this document type'
    }
  };
}

return {
  json: {
    error: false,
    documentType: body.document_type,
    projectId: body.project_id || null,
    filters: body.filters || {},
    recipientEmail: body.recipient_email || null
  }
};

// -----------------------------
// 1️⃣ Input data
// -----------------------------
const projectData = $('Get many database pages1').first().json;

const projectCode = projectData.property_reference.split('-')[0];
const records = $('Get many database pages1').all();

// -----------------------------
// 2️⃣ Document type mapping
// -----------------------------
const validTypes = ['dcn', 'vo', 'vo_register', 'si'];
const defaultTitles = {
  'vo_register': 'Variation Order Register',
  'vo': 'Variation Order',
  'dcn': 'DCN',
  'si': 'SI'
};

const docTypeInput = $('Validate Request').first().json.documentType;

if (!docTypeInput || !validTypes.includes(docTypeInput)) {
  return { 
    json: { error: true, message: 'Invalid document_type. Must be one of: ' + validTypes.join(', ') } 
  };
}

const documentTitle = defaultTitles[docTypeInput];

// -----------------------------
// 3️⃣ Utility: format date
// -----------------------------
function formatDate(dateStr) {
  if (!dateStr) return '-';
  const d = new Date(dateStr);
  return d.toLocaleDateString();
}

// -----------------------------
// 4️⃣ Generate table rows dynamically
// -----------------------------
function generateRows(records, type) {
  if (!records || records.length === 0) {
    return `<tr><td colspan="6" style="text-align:center; padding:20px; color:#6b7280;">No records found</td></tr>`;
  }

  return records.map(r => {
    const docNo = r.json.property_reference;
    const subject = r.json.property_subject || '-';
    const issueDate = formatDate(
      r.json.property_issue_date?.start ||
      r.json.property_received_date?.start ||
      r.json.jsonproperty_created_time
    );
    const status = r.json.property_status || '-';
    const contractorEmail = r.json.property_email_contractor || '-';
    const ackDate = formatDate(r.json.property_acknowledgment_date?.start || r.property_acknowledgment_date);
    const dueDate = formatDate(r.json.property_required_by_date?.start || r.property_required_by_date);

    const statusColors = {
      'Draft': '#9ca3af',
      'Issued': '#3b82f6',
      'Acknowledged': '#10b981',
      'Closed': '#6b7280',
      'Published': '#10b981',
      'Open': '#f59e0b',
      'Overdue': '#dc2626'
    };
    const statusColor = statusColors[status] || '#6b7280';

    const commonCells = {
      docNo: `<td>${docNo}</td>`,
      subject: `<td>${subject}</td>`,
      issueDate: `<td class="center">${issueDate}</td>`,
      status: `<td class="center"><span style="background:${statusColor}; color:white; padding:4px 8px; border-radius:4px; font-size:11px;">${status}</span></td>`,
      ackDate: `<td class="center">${ackDate}</td>`,
      contractorEmail: `<td class="center">${contractorEmail}</td>`,
      dueDate: `<td class="center">${dueDate}</td>`
    };

    switch(type) {
      case 'vo_register':
      case 'vo':
        return `<tr>${commonCells.docNo}${commonCells.subject}${commonCells.issueDate}${commonCells.status}${commonCells.ackDate}${commonCells.contractorEmail}</tr>`;
      case 'si':
      case 'dcn':
        return `<tr>${commonCells.docNo}${commonCells.subject}${commonCells.issueDate}${commonCells.status}${commonCells.contractorEmail}</tr>`;
      default:
        return '';
    }
  }).join('');
}

// -----------------------------
// 5️⃣ Table headers dynamically
// -----------------------------
let tableHeaders = '';
switch(docTypeInput) {
  case 'vo_register':
  case 'vo':
    tableHeaders = `<tr>
      <th>Reference</th>
      <th>Subject</th>
      <th class="center">Issue Date</th>
      <th class="center">Status</th>
      <th class="center">Acknowledged</th>
      <th class="center">Contractor Email</th>
    </tr>`;
    break;
  case 'si':
  case 'dcn':
    tableHeaders = `<tr>
      <th>Doc No</th>
      <th>Subject</th>
      <th class="center">Issue Date</th>
      <th class="center">Status</th>
      <th class="center">Contractor Email</th>
    </tr>`;
    break;
}

// -----------------------------
// 6️⃣ Generate HTML
// -----------------------------
const tableRows = generateRows(records, docTypeInput);
const impactSummary = $('Get many database pages1').first().json.property_description || '-';

const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>${documentTitle} - ${projectCode}</title>
  <style>
    body { font-family: Arial, sans-serif; font-size: 10pt; color: #1f2937; margin: 20px; }
    .header { border-bottom: 3px solid #2563eb; padding-bottom: 15px; margin-bottom: 20px; }
    .title { font-size: 20pt; font-weight: bold; color: #2563eb; margin:0; }
    .subtitle { font-size: 12pt; color: #666; margin:5px 0; }
    table { width: 100%; border-collapse: collapse; margin-top: 20px; }
    thead { background: #f3f4f6; }
    th, td { padding: 12px; text-align: left; border-bottom: 1px solid #ddd; }
    th { font-weight: bold; border-bottom: 2px solid #2563eb; }
    td.center, th.center { text-align:center; }
    .summary { margin-top: 20px; padding: 15px; background:#f9fafb; border-left: 4px solid #2563eb; }
    .footer { margin-top: 20px; font-size: 8pt; color:#666; border-top:1px solid #ddd; padding-top:5px; }
  </style>
</head>
<body>

  <div class="header">
    <div class="title">${documentTitle}</div>
    <div class="subtitle">${projectCode}</div>
    <div style="font-size:9pt; color:#999; margin-top:10px;">Generated: ${new Date().toLocaleDateString()}</div>
  </div>

  <table>
    <thead>${tableHeaders}</thead>
    <tbody>${tableRows}</tbody>
  </table>

  <div class="summary">
    <strong>Summary:</strong> Total Records: ${records.length || 0}<br>
    <strong>Details:</strong> ${impactSummary}
  </div>

  <div class="footer">
    ${documentTitle} | ${projectCode} | Page 1 of 1
  </div>

</body>
</html>
`;

// -----------------------------
